import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import Services from './components/Services';
import BillingForm from './components/BillingForm';
import SavedBills from './components/SavedBills';
import InvoicePreview from './components/InvoicePreview';
import Login from './components/Login';
import AdminServices from './components/AdminServices';
import { Phone, MapPin, ShieldCheck, LogOut } from 'lucide-react';

const DEFAULT_SERVICES = [
  { id: 1, title: "House Wiring", description: "Complete house wiring for new and old constructions." },
  { id: 2, title: "Fan & Light Fitting", description: "Installation of all types of fans, LED lights, and chandeliers." },
  { id: 3, title: "Switch Board Repair", description: "Repairing and replacement of burnt or faulty switches." },
  { id: 4, title: "Inverter & Meter Work", description: "New inverter installation and official meter shifting." },
  { id: 5, title: "Cooler & AC Repair", description: "Electrical maintenance and repair for cooling systems." },
  { id: 6, title: "Kitchen Appliances", description: "Repair of mixers, ovens, and chimneys." },
  { id: 7, title: "1BHK/2BHK Wiring", description: "Fixed price packages for apartment wiring." },
];

function App() {
  const [activeTab, setActiveTab] = useState('home');
  const [savedInvoices, setSavedInvoices] = useState([]);
  const [selectedInvoice, setSelectedInvoice] = useState(null);
  const [services, setServices] = useState(DEFAULT_SERVICES);
  const [isAdmin, setIsAdmin] = useState(false);

  // Initialize data
  useEffect(() => {
    const storedInvoices = localStorage.getItem('electrician_invoices');
    if (storedInvoices) setSavedInvoices(JSON.parse(storedInvoices));

    const storedServices = localStorage.getItem('electrician_services');
    if (storedServices) {
      setServices(JSON.parse(storedServices));
    } else {
      localStorage.setItem('electrician_services', JSON.stringify(DEFAULT_SERVICES));
    }

    const adminStatus = localStorage.getItem('electrician_admin');
    if (adminStatus === 'true') setIsAdmin(true);
  }, []);

  const handleLogin = () => {
    setIsAdmin(true);
    localStorage.setItem('electrician_admin', 'true');
    setActiveTab('admin');
  };

  const handleLogout = () => {
    setIsAdmin(false);
    localStorage.removeItem('electrician_admin');
    setActiveTab('home');
  };

  const updateServices = (newServices) => {
    setServices(newServices);
    localStorage.setItem('electrician_services', JSON.stringify(newServices));
  };

  const saveInvoice = (invoice) => {
    const updated = [invoice, ...savedInvoices];
    setSavedInvoices(updated);
    localStorage.setItem('electrician_invoices', JSON.stringify(updated));
    setSelectedInvoice(invoice);
    setActiveTab('preview');
  };

  const viewInvoice = (invoice) => {
    setSelectedInvoice(invoice);
    setActiveTab('preview');
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar
        activeTab={activeTab}
        setActiveTab={setActiveTab}
        isAdmin={isAdmin}
        onLogout={handleLogout}
      />

      <main className="flex-grow container mx-auto px-4 py-8">
        {activeTab === 'home' && (
          <>
            <Hero setActiveTab={setActiveTab} />
            <Services services={services} />
            <section className="mt-16 glass p-8 rounded-2xl text-center border-yellow-500/20">
              <h2 className="text-3xl font-bold mb-4 gold-text-gradient">24/7 Emergency Service Available</h2>
              <p className="text-gray-400 mb-6 uppercase tracking-widest text-sm font-bold">Fast • Reliable • Professional</p>
              <div className="flex flex-wrap justify-center gap-4">
                <a href="tel:7498045041" className="bg-yellow-500 hover:bg-yellow-600 text-black font-bold py-3 px-8 rounded-full transition-all flex items-center gap-2">
                  <Phone size={20} /> Call Sohail
                </a>
                <a href="https://wa.me/917498045041" target="_blank" rel="noreferrer" className="bg-green-600 hover:bg-green-700 text-white font-bold py-3 px-8 rounded-full transition-all flex items-center gap-2">
                  WhatsApp Now
                </a>
              </div>
            </section>
          </>
        )}

        {activeTab === 'billing' && <BillingForm onSave={saveInvoice} />}

        {activeTab === 'history' && <SavedBills invoices={savedInvoices} onView={viewInvoice} />}

        {activeTab === 'preview' && selectedInvoice && (
          <div className="max-w-4xl mx-auto">
             <button
              onClick={() => setActiveTab('history')}
              className="mb-4 text-yellow-500 hover:underline flex items-center gap-2 no-print"
            >
              ← Back to History
            </button>
            <InvoicePreview invoice={selectedInvoice} />
          </div>
        )}

        {activeTab === 'login' && <Login onLogin={handleLogin} />}

        {activeTab === 'admin' && isAdmin && (
          <AdminServices services={services} onUpdate={updateServices} />
        )}
      </main>

      <footer className="mt-auto py-8 border-t border-gray-800 bg-black/50 no-print">
        <div className="container mx-auto px-4 grid grid-cols-1 md:grid-cols-3 gap-8">
          <div className="text-center md:text-left">
            <h3 className="text-xl font-bold text-yellow-500 mb-4 flex items-center justify-center md:justify-start gap-2">
              Sohail Mulani
            </h3>
            <p className="text-gray-400">Your trusted partner for all electrical needs in Nashik.</p>
            {isAdmin ? (
               <button onClick={handleLogout} className="mt-4 flex items-center gap-2 text-red-500 hover:text-red-400 text-sm font-bold transition">
                <LogOut size={16} /> LOGOUT FROM ADMIN
               </button>
            ) : (
              <button onClick={() => setActiveTab('login')} className="mt-4 flex items-center gap-2 text-gray-500 hover:text-yellow-500 text-sm transition">
                <ShieldCheck size={16} /> Admin Portal
              </button>
            )}
          </div>
          <div className="text-center md:text-left">
            <h4 className="font-bold mb-4">Contact Details</h4>
            <ul className="text-gray-400 space-y-2">
              <li className="flex items-center justify-center md:justify-start gap-2">
                <Phone size={16} className="text-yellow-500" /> 7498045041
              </li>
              <li className="flex items-center justify-center md:justify-start gap-2">
                <MapPin size={16} className="text-yellow-500" /> Nashik, Maharashtra
              </li>
            </ul>
          </div>
          <div className="text-center md:text-left">
            <h4 className="font-bold mb-4">Quality Assurance</h4>
            <p className="text-gray-400">Standardized Pricing • Verified Electricians • 100% Satisfaction</p>
          </div>
        </div>
        <div className="text-center mt-8 text-gray-600 text-xs uppercase tracking-widest border-t border-gray-900 pt-8">
          © {new Date().getFullYear()} Sohail Mulani | Multi-Service Electrical Solutions
        </div>
      </footer>
    </div>
  );
}

export default App;
